"""AsyncWebsocketConsumer — streams Ollama tokens to the client."""
import json
import os
from collections.abc import AsyncIterator

from channels.generic.websocket import AsyncWebsocketConsumer
from langchain_ollama import ChatOllama


def _ollama_client() -> ChatOllama:
    """Build a ChatOllama client from environment variables."""
    return ChatOllama(
        model=os.environ["OLLAMA_MODEL"],
        base_url=os.environ["OLLAMA_HOST"],
    )


async def _stream_tokens(prompt: str) -> AsyncIterator[str]:
    """Yield tokens from Ollama via langchain streaming."""
    client = _ollama_client()
    async for chunk in client.astream(prompt):
        # Handle both LangChain AIMessage chunks and raw strings
        if isinstance(chunk, str):
            yield chunk
        else:
            content = getattr(chunk, "content", None)
            if content:
                yield content


class ChatConsumer(AsyncWebsocketConsumer):
    """WebSocket consumer that streams Ollama responses token-by-token."""

    async def connect(self) -> None:
        self.history: list[dict[str, str]] = []
        await self.accept()

    async def disconnect(self, _close_code: int) -> None:
        pass

    async def receive(self, text_data: str) -> None:
        try:
            payload = json.loads(text_data)
        except json.JSONDecodeError:
            await self.send(text_data=json.dumps(
                {"type": "error", "message": "Invalid JSON"}
            ))
            return

        if payload.get("type") != "message":
            return

        user_content = payload.get("content", "").strip()
        if not user_content:
            await self.send(text_data=json.dumps(
                {"type": "error", "message": "Empty message"}
            ))
            return

        self.history.append({"role": "user", "content": user_content})
        prompt = "\n".join(f"{m['role']}: {m['content']}" for m in self.history)

        try:
            assistant_text = ""
            async for token in _stream_tokens(prompt):
                await self.send(text_data=json.dumps(
                    {"type": "token", "content": token}
                ))
                assistant_text += token

            self.history.append({"role": "assistant", "content": assistant_text})

        except Exception as exc:  # noqa: BLE001
            await self.send(text_data=json.dumps(
                {"type": "error", "message": str(exc)}
            ))

        await self.send(text_data=json.dumps({"type": "done"}))

