{% extends "base.html" %}
{% load static %}

{% block title %}Chat{% endblock %}

{% block body %}
<div class="flex flex-col h-screen max-w-3xl mx-auto w-full px-4 py-6">

    <header class="flex-shrink-0 pb-4 border-b border-gray-200">
        <h1 class="text-xl font-semibold text-gray-800">Ollama Chat</h1>
    </header>

    <div id="messages" class="flex-1 overflow-y-auto py-4 space-y-4">
        <p id="empty-placeholder" class="text-gray-400 text-center text-sm mt-8">
            Send a message to start the conversation.
        </p>
    </div>

    <div id="thinking" class="hidden py-2">
        <span class="text-gray-400 text-sm flex items-center gap-2">
            <span class="animate-pulse">...</span> Thinking
        </span>
    </div>

    <form id="chat-form" class="flex-shrink-0 pt-4">
        <div class="flex gap-3">
            <textarea
                id="message-input"
                name="content"
                rows="1"
                placeholder="Type a message..."
                class="flex-1 resize-none rounded-lg border border-gray-300 px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                autofocus
            ></textarea>
            <button
                type="submit"
                class="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors"
            >Send</button>
        </div>
    </form>

</div>

<script>
(function () {
    "use strict";

    const messagesEl = document.getElementById("messages");
    const placeholderEl = document.getElementById("empty-placeholder");
    const form = document.getElementById("chat-form");
    const input = document.getElementById("message-input");
    const thinking = document.getElementById("thinking");

    let ws = null;

    function escHtml(str) {
        const d = document.createElement("div");
        d.textContent = str;
        return d.innerHTML;
    }

    function scrollBottom() {
        messagesEl.scrollTop = messagesEl.scrollHeight;
    }

    function appendMessage(role, content) {
        const roleClass = role === "user" ? "message-user" : "message-assistant";
        const justifyClass = role === "user" ? "justify-end" : "justify-start";
        const div = document.createElement("div");
        div.innerHTML = "<div class=\"flex " + justifyClass + "\">" +
            "<div class=\"" + roleClass + "\" style=\"max-width: 80%;\">" +
            escHtml(content) + "</div></div>";
        messagesEl.appendChild(div.firstElementChild);
        scrollBottom();
    }

    function openWS() {
        const sessionId = Math.random().toString(36).slice(2);
        const proto = location.protocol === "https:" ? "wss" : "ws";
        ws = new WebSocket(proto + "://" + location.host + "/ws/chat/" + sessionId + "/");

        ws.onopen = function () {
            const content = input.value.trim();
            if (content) {
                ws.send(JSON.stringify({ type: "message", content: content }));
            }
        };

        ws.onmessage = function (e) {
            const data = JSON.parse(e.data);
            if (data.type === "token") {
                let last = messagesEl.querySelector(".message-assistant:last-child");
                if (!last) {
                    appendMessage("assistant", "");
                    last = messagesEl.querySelector(".message-assistant:last-child");
                }
                last.textContent += data.content;
                scrollBottom();
            } else if (data.type === "done") {
                thinking.classList.add("hidden");
                ws.close();
                ws = null;
            } else if (data.type === "error") {
                thinking.classList.add("hidden");
                appendMessage("assistant", "[Error] " + data.message);
                ws.close();
                ws = null;
            }
        };

        ws.onerror = function () {
            thinking.classList.add("hidden");
            appendMessage("assistant", "[Connection error]");
        };

        ws.onclose = function () {
            thinking.classList.add("hidden");
        };
    }

    form.addEventListener("submit", function (e) {
        e.preventDefault();
        const content = input.value.trim();
        if (!content) return;

        if (placeholderEl) placeholderEl.remove();

        appendMessage("user", content);
        input.value = "";
        thinking.classList.remove("hidden");
        scrollBottom();

        openWS();
    });
})();
</script>
{% endblock %}

